1	/**
2	 * OKKI 数据抓取 — Playwright 复用 Profile 4（不触发新认证）
3	 *
4	 * 原理：
5	 * - 直接用你 Chrome 的 Profile 4 启动浏览器
6	 * - OKKI 登录 cookie 已在 Profile 中，打开就是已登录
7	 * - 拦截所有 OKKI API 响应，完整数据落盘
8	 * - 不经过 SSO 认证层 → 同事账号零影响
9	 *
10	 * 使用：
11	 * 1. 关闭 Chrome（Profile 不能同时被两个进程用）
12	 * 2. node scripts/scrape_okki.js
13	 * 3. 浏览器会自动打开 crm.xiaoman.cn
14	 * 4. 你正常浏览客户页面，所有 API 数据自动抓取
15	 * 5. 完成后 Ctrl+C 停止，数据在 data/ 目录
16	 *
17	 * 也支持指定客户：
18	 *   node scripts/scrape_okki.js "Peggy Hamungala"
19	 */
20	
21	const { chromium } = require('playwright');
22	const path = require('path');
23	const fs = require('fs');
24	
25	const PROFILE_PATH = 'C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\User Data\\Profile 4';
26	const OUTPUT_DIR = path.join(__dirname, '..', 'data');
27	const TARGET_CUSTOMER = process.argv[2];
28	
29	// 确保输出目录存在
30	if (!fs.existsSync(OUTPUT_DIR)) {
31	  fs.mkdirSync(OUTPUT_DIR, { recursive: true });
32	}
33	
34	const captured = {
35	  apiResponses: [],
36	  customers: [],
37	  currentPage: null,
38	};
39	
40	async function main() {
41	  console.log('[OKKI Scraper] 启动中...');
42	  console.log(`[OKKI Scraper] Profile: ${PROFILE_PATH}`);
43	
44	  const browser = await chromium.launchPersistentContext(PROFILE_PATH, {
45	    channel: 'chrome',
46	    headless: false,
47	    viewport: { width: 1440, height: 900 },
48	    // 只拦截 OKKI 相关请求，不碰其他站点
49	  });
50	
51	  const page = await browser.newPage();
52	
53	  // ===== 拦截所有 OKKI API 响应 =====
54	  page.on('response', async (response) => {
55	    const url = response.url();
56	    // 只捕获 OKKI CRM 的 API 请求
57	    if (!url.includes('xiaoman') && !url.includes('okki')) return;
58	
59	    try {
60	      const contentType = response.headers()['content-type'] || '';
61	      if (!contentType.includes('json')) return;
62	
63	      const body = await response.json().catch(() => null);
64	      if (!body) return;
65	
66	      const entry = {
67	        time: new Date().toISOString(),
68	        url: url.split('?')[0], // 去掉 query 参数去重用
69	        fullUrl: url,
70	        status: response.status(),
71	        data: body,
72	      };
73	
74	      captured.apiResponses.push(entry);
75	      console.log(`  [API] ${response.status()} ${entry.url}`);
76	
77	      // 尝试提取客户列表
78	      if (body.data?.list || body.data?.records || body.list || body.records) {
79	        const list = body.data?.list || body.data?.records || body.list || body.records;
80	        if (Array.isArray(list)) {
81	          for (const c of list) {
82	            const name = c.name || c.companyName || c.company_name || c.customerName || 'unknown';
83	            if (!captured.customers.find(x => x.name === name)) {
84	              captured.customers.push({ name, raw: c });
85	            }
86	          }
87	          console.log(`  → 捕获 ${list.length} 个客户`);
88	        }
89	      }
90	    } catch (e) {
91	      // 忽略无法解析的响应
92	    }
93	  });
94	
95	  // ===== 导航到 OKKI =====
96	  console.log('[OKKI Scraper] 导航到 crm.xiaoman.cn ...');
97	  await page.goto('https://crm.xiaoman.cn/', { waitUntil: 'domcontentloaded', timeout: 30000 });
98	
99	  // 等待用户确认登录状态
100	  console.log('[OKKI Scraper] 浏览器已打开。检查登录状态...');
101	
102	  // 等页面稳定
103	  await page.waitForTimeout(3000);
104	
105	  const currentUrl = page.url();
106	  console.log(`[OKKI Scraper] 当前页面: ${currentUrl}`);
107	
108	  // 保存当前页面快照
109	  captured.currentPage = {
110	    url: currentUrl,
111	    title: await page.title(),
112	  };
113	
114	  if (TARGET_CUSTOMER) {
115	    // ===== 指定客户模式 =====
116	    console.log(`[OKKI Scraper] 搜索客户: "${TARGET_CUSTOMER}"`);
117	
118	    // 尝试找搜索框
119	    const searchSelectors = [
120	      'input[placeholder*="搜索"]',
121	      'input[placeholder*="search"]',
122	      'input[placeholder*="Search"]',
123	      'input[class*="search"]',
124	      'input[class*="Search"]',
125	      '.search-input input',
126	      '[class*="search"] input',
127	    ];
128	
129	    let searched = false;
130	    for (const sel of searchSelectors) {
131	      const el = page.locator(sel).first();
132	      if (await el.isVisible({ timeout: 1000 }).catch(() => false)) {
133	        await el.fill(TARGET_CUSTOMER);
134	        await page.keyboard.press('Enter');
135	        await page.waitForTimeout(2000);
136	        searched = true;
137	        console.log(`[OKKI Scraper] 已搜索: "${TARGET_CUSTOMER}"`);
138	        break;
139	      }
140	    }
141	
142	    if (!searched) {
143	      console.log('[OKKI Scraper] 未找到搜索框，请手动搜索后按 Enter 继续...');
144	      // 等待用户手动操作
145	      await page.waitForTimeout(30000);
146	    }
147	
148	    // 点击第一个客户
149	    const rowSelectors = [
150	      'tr[class*="row"]',
151	      '[class*="table"] tr',
152	      '[class*="list"] [class*="item"]',
153	      'tbody tr',
154	    ];
155	    for (const sel of rowSelectors) {
156	      const row = page.locator(sel).first();
157	      if (await row.isVisible({ timeout: 500 }).catch(() => false)) {
158	        await row.click();
159	        await page.waitForTimeout(2000);
160	        console.log('[OKKI Scraper] 已打开客户详情');
161	        break;
162	      }
163	    }
164	  }
165	
166	  // 持续抓取
167	  console.log('');
168	  console.log('========================================');
169	  console.log('[OKKI Scraper] 抓取中... 正常浏览即可');
170	  console.log('[OKKI Scraper] 每个 API 响应自动捕获');
171	  console.log('[OKKI Scraper] 按 Ctrl+C 停止并保存');
172	  console.log('========================================');
173	
174	  // 每 30 秒保存一次中间结果
175	  const saveInterval = setInterval(saveData, 30000);
176	
177	  // 优雅退出
178	  process.on('SIGINT', async () => {
179	    clearInterval(saveInterval);
180	    console.log('\n[OKKI Scraper] 正在保存...');
181	    saveData();
182	    await browser.close();
183	    console.log('[OKKI Scraper] 完成。');
184	    process.exit(0);
185	  });
186	
187	  // 保持运行
188	  await new Promise(() => {});
189	}
190	
191	function saveData() {
192	  if (captured.apiResponses.length === 0) {
193	    console.log('[Save] 暂无数据');
194	    return;
195	  }
196	
197	  const timestamp = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
198	  const filepath = path.join(OUTPUT_DIR, `okki_capture_${timestamp}.json`);
199	
200	  // 去重
201	  const seen = new Set();
202	  const unique = captured.apiResponses.filter(e => {
203	    const key = e.url + JSON.stringify(e.data).substring(0, 200);
204	    if (seen.has(key)) return false;
205	    seen.add(key);
206	    return true;
207	  });
208	
209	  fs.writeFileSync(filepath, JSON.stringify({
210	    capturedAt: timestamp,
211	    page: captured.currentPage,
212	    customerCount: captured.customers.length,
213	    apiCount: unique.length,
214	    customers: captured.customers,
215	    apiResponses: unique,
216	  }, null, 2));
217	
218	  console.log(`[Save] ${unique.length} 条API + ${captured.customers.length} 个客户 → ${filepath}`);
219	}
220	
221	main().catch(err => {
222	  console.error('[OKKI Scraper] 错误:', err.message);
223	  process.exit(1);
224	});
