1	const fs = require('fs');
2	const path = require('path');
3	
4	const chatDir = path.join(__dirname, '..', 'data', 'chat_history');
5	const SELF_UID = '2500000853693@icbu';
6	
7	const sysPatterns = [
8	  '自动接待将不再触发', 'Since you have read the conversation',
9	  'Marco大模型翻译', '阿里国际Marco大模型翻译',
10	  '买家有流失风险', 'Buyer has churn risk',
11	  '一旦离开平台发生纠纷或欺诈', '由于您介入该会话', 'Due to your intervention',
12	  '反馈', 'AI给您生成了一条回复建议',
13	  'You have a visitor', 'This buyer has been pre-screened',
14	];
15	
16	function isSystemMsg(content) {
17	  if (!content) return true;
18	  for (const p of sysPatterns) {
19	    if (content.includes(p)) return true;
20	  }
21	  return false;
22	}
23	
24	function isSelf(msg) {
25	  return msg?.message?.sender?.uid === SELF_UID;
26	}
27	
28	const TARGETS = [
29	  { cid: '133756334970-2500000853693#11011@icbu', name: 'Mona almuharraqy', country: 'BH' },
30	  { cid: '2500000853693-4500020103986#11011@icbu', name: 'ali Amjid', country: 'ZA' },
31	  { cid: '2034012960891-2500000853693#11011@icbu', name: 'Christabel Kanunsha', country: 'ZM' },
32	  { cid: '2500000853693-3500017223847#11011@icbu', name: 'jonathan aston', country: 'GH' },
33	  { cid: '133712154113-2500000853693#11011@icbu', name: 'diego vargas', country: 'ES' },
34	  { cid: '2500000853693-4500046370107#11011@icbu', name: 'Aloh Voma', country: 'US' },
35	  { cid: '2500000853693-4500009336909#11011@icbu', name: 'Mezna Alawfi', country: 'OM' },
36	  { cid: '2034038976476-2500000853693#11011@icbu', name: 'WELE Mounia', country: 'TG' },
37	  { cid: '2500000853693-4500047334590#11011@icbu', name: 'Rosette Ngoy', country: 'CD' },
38	  { cid: '133605767280-2500000853693#11011@icbu', name: 'Inderpreet kaur', country: 'US' },
39	];
40	
41	for (const t of TARGETS) {
42	  const fileName = t.cid.replace(/#/g, '_').replace(/@/g, '_') + '.json';
43	  const filePath = path.join(chatDir, fileName);
44	
45	  console.log(`\n${'='.repeat(60)}`);
46	  console.log(`${t.name} | ${t.country}`);
47	  console.log(`${'='.repeat(60)}`);
48	
49	  if (!fs.existsSync(filePath)) {
50	    console.log('FILE NOT FOUND');
51	    continue;
52	  }
53	
54	  const data = JSON.parse(fs.readFileSync(filePath, 'utf8'));
55	  const messages = data.messages || [];
56	
57	  // Filter real messages
58	  const realMessages = messages.filter(m => {
59	    const ext = m?.message?.extension?.basicMessageInfo;
60	    if (ext) {
61	      try {
62	        const info = JSON.parse(ext);
63	        if (info.systemMessage === true || info.autoReply === true) return false;
64	      } catch(e) {}
65	    }
66	    return !isSystemMsg(m?.message?.content?.text?.content || '');
67	  });
68	
69	  // Show last 25 messages (chronological)
70	  const recent = realMessages.slice(-25);
71	  for (const m of recent) {
72	    const content = (m?.message?.content?.text?.content || '').substring(0, 150);
73	    const ts = m?.message?.createAt || 0;
74	    const date = new Date(ts).toISOString().replace('T', ' ').substring(0, 19);
75	    const isMe = isSelf(m);
76	    const prefix = isMe ? '我方' : '客户';
77	    console.log(`  [${date}] ${prefix}: ${content}`);
78	  }
79	
80	  // Summary stats
81	  const clientMsgs = realMessages.filter(m => !isSelf(m));
82	  const selfMsgs = realMessages.filter(m => isSelf(m));
83	  const lastClientTs = clientMsgs.length > 0 ? Math.max(...clientMsgs.map(m => m?.message?.createAt || 0)) : 0;
84	  const lastSelfTs = selfMsgs.length > 0 ? Math.max(...selfMsgs.map(m => m?.message?.createAt || 0)) : 0;
85	
86	  console.log(`\n  统计: 总${messages.length}/有效${realMessages.length} | 客户${clientMsgs.length}条 | 我方${selfMsgs.length}条`);
87	  console.log(`  最后客户消息: ${lastClientTs ? new Date(lastClientTs).toISOString().replace('T',' ').substring(0,19) : '无'}`);
88	  console.log(`  最后我方消息: ${lastSelfTs ? new Date(lastSelfTs).toISOString().replace('T',' ').substring(0,19) : '无'}`);
89	}
