102	
103	  if (lastCust > 30) {
104	    const from = stage;
105	    // Exception: 已签收 has longer tolerance
106	    if (from === '已签收' && lastCust <= 90) {
107	      priority = 'idle';
108	      reason = '已签收，静默' + lastCust + '天';
109	      return { stage, priority, reason };
110	    }
111	    stage = '搁置';
112	    priority = 'idle';
113	    reason = '静默' + lastCust + '天（从' + from + '掉出）';
114	    return { stage, priority, reason };
115	  }
116	
117	  // === PRIORITY FOR ACTIVE STAGE (<30d silence) ===
118	  // Now: <3d silence or ball-in-our-court
119	  // Soon: 3-14d for quote/negotiation/shipping, 3-7d for exploration
120	  // Idle: 14-30d for most, 7-30d for simple exploration
121	
122	  if (lastCust <= 1) {
123	    priority = 'now';
124	  } else if (lastCust <= 3) {
125	    priority = 'now';  // 3天内客户有回应，必须马上跟进
126	  } else if (lastCust <= 7) {
127	    priority = 'soon';
128	  } else if (lastCust <= 14) {
129	    if (stage === '需求探索' && totalMsgs < 10) {
130	      priority = 'idle';
131	    } else {
132	      priority = 'soon';
133	    }
134	  } else {
135	    // 14-30d
136	    if (['报价已发', '谈判中', '已发货/在途', '待付款'].includes(stage)) {
137	      priority = 'soon';
138	    } else {
139	      priority = 'idle';
140	    }
141	  }
142	
143	  // Override: ball in our court
144	  if (dir === 'to_us' && lastCust <= 7) {
145	    priority = 'now';
146	  }
147	
148	  // Override: supplier made a promise but never delivered (≥14d silence)
149	  if (hasSupplierPromise && lastCust >= 14 && lastCust <= 60 && stage !== '搁置') {
150	    priority = 'now';
151	    reason = (reason || '') + '；我方有未兑现承诺';
152	  }
153	
154	  if (!reason) {
155	    const silLabel = lastCust <= 3 ? '活跃' : (lastCust <= 7 ? '短期沉默' : (lastCust <= 14 ? '中期沉默' : '长期沉默'));
156	    reason = stage + '中，' + silLabel + lastCust + '天';
157	  }
158	
159	  return { stage, priority, reason };
160	}
161	
162	function correctGrade(c, snippetText) {
163	  let grade = c.grade;
164	  let override = null;
165	
166	  // Phantom / non-customer accounts
167	  if (['Leon Scott Kennedy', 'Anne Shen', 'User name', '(未知)', 'd zm'].includes(c.name)) {
168	    return { grade: 'D', override: 'D' };
169	  }
170	
171	  // Personal use → downgrade
172	  if (/(?:uso personal|personal use|for myself|my baby|mon bébé|primipare)/i.test(snippetText) && c.totalMsgs < 50) {
173	    if (grade === 'A') return { grade: 'B', override: 'B' };
174	    if (grade === 'B') return { grade: 'C', override: 'C' };
175	  }
176	
177	  // Adult clothing mismatch → D (but NOT if they have existing orders)
178	  if (/(?:ropa de mujer|women.*cloth|adult.*cloth|period pant|seamless pant|femme.*adulte|pour femme)/i.test(snippetText)) {
179	    if (/(?:solo.*bebé|solo.*niño|only.*baby|only.*infant|only.*kid|fabricamos.*bebé|manufacture.*baby|only make.*baby)/i.test(snippetText)) {
180	      if (grade !== 'S' && !(c.order && c.order.matched)) {
181	        return { grade: 'D', override: 'D' };
182	      }
183	    }
184	  }
185	
186	  // Suspicious names → D (now covered by ghost list above; kept as safety net)
187	  if (c.name === 'User name' || c.name === '(未知)') {
188	    return { grade: 'D', override: 'D' };
189	  }
190	
191	  // Dead accounts: 1 customer message + 60d+ silence
192	  if (c.customerMsgs <= 1 && c.lastCustomerMsgDays > 60 && c.totalMsgs <= 5) {
193	    if (grade === 'A' || grade === 'B') return { grade: 'D', override: 'D' };
194	  }
195	
196	  return { grade, override };
197	}
198	
